interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  stock: number;
}

class Product {
  constructor(
    public id: string,
    public name: string,
    public description: string,
    public price: number,
    public stock: number
  ) {}

  applyDiscount(discountPercent: number): void {
    this.price = this.price - this.price * (discountPercent / 100);
  }

  updateStock(quantity: number): void {
    this.stock += quantity;
  }
}

enum UserRole {
  CUSTOMER = 'CUSTOMER',
  ADMIN = 'ADMIN',
  SELLER = 'SELLER'
}

class User {
  constructor(
    public id: string,
    public name: string,
    public email: string,
    public role: UserRole
  ) {}

  isAdmin(): boolean {
    return this.role === UserRole.ADMIN;
  }
}

class Order {
  constructor(
    public id: string,
    public user: User,
    public products: Product[],
    public orderDate: Date
  ) {}

  getTotal(): number {
    return this.products.reduce((sum, product) => sum + product.price, 0);
  }
}

function printLength(value: string | null) {
  if (value !== null) {
    // Here, TypeScript knows 'value' is a string
    console.log(value.length);
  } else {
    console.log('No value provided');
  }
}

function handleError(error: unknown) {
  if (error instanceof Error) {
    // Narrowed from 'unknown' to 'Error'
    console.log('Error message:', error.message);
  } else {
    console.log('Unexpected error', error);
  }
}

function isString(value: unknown): value is string {
  return typeof value === 'string';
}

function printValue(value: unknown) {
  if (isString(value)) {
    // Within this block, TypeScript knows 'value' is a string
    console.log(value.toUpperCase());
  } else {
    console.log('Not a string');
  }
}

